class Solution:
    def minCut(self, s):
        n = len(s)
        import functools
        def is_pal(a, b):
            while a < b:
                if s[a] != s[b]:
                    return False
                a += 1
                b -= 1
            return True
        INF = float('inf')
        dp = [INF] * (n + 1)
        dp[0] = -1
        for i in range(1, n + 1):
            for j in range(i):
                if is_pal(j, i - 1):
                    if dp[j] + 1 < dp[i]:
                        dp[i] = dp[j] + 1
        return dp[n]

