class Solution:
    def minCut(self, s):
        n = len(s)
        pal = [[False] * n for _ in range(n)]
        for i in range(n):
            pal[i][i] = True
        for length in range(2, n + 1):
            for j in range(0, n - length + 1):
                i = j + length - 1
                if s[j] == s[i] and (length == 2 or pal[j+1][i-1]):
                    pal[j][i] = True
        cuts = [0] * n
        for i in range(n):
            if pal[0][i]:
                cuts[i] = 0
            else:
                best = i
                for j in range(1, i + 1):
                    if pal[j][i] and cuts[j-1] + 1 < best:
                        best = cuts[j-1] + 1
                cuts[i] = best
        return cuts[n-1]

