var minCut = function(s) {
    const n = s.length;
    const pal = Array.from({length: n}, () => new Array(n).fill(false));
    for (let i = 0; i < n; i++) pal[i][i] = true;
    for (let length = 2; length <= n; length++) {
        for (let j = 0; j + length - 1 < n; j++) {
            const i = j + length - 1;
            if (s[j] === s[i] && (length === 2 || pal[j+1][i-1])) pal[j][i] = true;
        }
    }
    const cuts = new Array(n).fill(0);
    for (let i = 0; i < n; i++) {
        if (pal[0][i]) { cuts[i] = 0; continue; }
        let best = i;
        for (let j = 1; j <= i; j++) {
            if (pal[j][i] && cuts[j-1] + 1 < best) best = cuts[j-1] + 1;
        }
        cuts[i] = best;
    }
    return cuts[n-1];
};
